16	//
17	// RBTDRI — tabtarget invocation layer for theurge
18	//
19	// Theurge invokes bottle operations exclusively through tabtargets, never
20	// reimplementing bash command logic. This module provides:
21	//
22	//   1. Tabtarget discovery — imprint-scoped, global, or nameplate-scoped
23	//   2. Tabtarget execution with BURV isolation — per-invocation output/temp dirs
24	//   3. Ifrit verdict parsing — extract verdict from ifrit stdout + exit code
25	//   4. BURV fact file reading — extract structured output from tabtarget results
26	
27	use std::path::{Path, PathBuf};
28	use std::process::Command;
29	
30	use crate::rbtdre_engine::rbtdre_Verdict;
31	use crate::rbtdgc_consts::RBTDGC_CRUCIBLE_BARK;
32	use crate::rbtdrx_platform::rbtdrx_native_to_posix;
33	
34	/// Ifrit binary name inside the bottle container.
35	const RBTDRI_IFRIT_BINARY: &str = "rbid";
36	
37	/// BUK dispatch output subdirectory — tabtargets write facts to BURV_OUTPUT_ROOT_DIR/current.
38	/// Matches BURD_OUTPUT_DIR = "${BURC_OUTPUT_ROOT_DIR}/current" from bud_dispatch.sh.
39	pub const RBTDRI_BURV_OUTPUT_SUBDIR: &str = "current";
40	
41	/// Env var name read by `buc_require` (buc_command.sh:335) to bypass interactive
42	/// confirmation prompts in non-interactive contexts (test fixtures, automation).
43	pub const RBTDRI_BURE_CONFIRM_KEY: &str = "BURE_CONFIRM";
44	
45	/// Value paired with `RBTDRI_BURE_CONFIRM_KEY` to skip the confirmation prompt.
46	pub const RBTDRI_BURE_CONFIRM_SKIP: &str = "skip";
47	
48	/// BUK dispatch env var carrying the temp root for theurge — anchors BURV
49	/// per-invoke temp dirs under temp-buk/ rather than /tmp/. Required: theurge
50	/// fails at startup if unset. Set by bud_dispatch.sh on every tabtarget call.
51	pub const RBTDRI_BURD_TEMP_DIR_KEY: &str = "BURD_TEMP_DIR";
52	
53	/// BURV invoke-directory name from a zero-based invoke count.
54	///
55	/// Single source of truth for the `invoke-NNNNN` naming pattern; tests call
56	/// this rather than hand-expanding the literal.
57	pub fn rbtdri_invoke_dir_name(invoke_num: u32) -> String {
58	    format!("invoke-{:05}", invoke_num)
59	}
60	
61	// ── Invocation result ────────────────────────────────────────
62	
63	/// Captured output from a tabtarget invocation.
64	#[derive(Debug)]
65	pub struct rbtdri_InvokeResult {
66	    pub stdout: String,
67	    pub stderr: String,
68	    pub exit_code: i32,
69	    pub burv_output: PathBuf,
70	}
71	
72	// ── Invocation context ───────────────────────────────────────
73	
74	/// Per-case invocation context. Tracks BURV isolation state so each tabtarget
75	/// invocation within a case gets its own output and temp directories, matching
76	/// the zbuto_invoke() pattern from buto_operations.sh.
77	///
78	/// `fixture` carries the fixture name. For crucible fixtures (tadmor/srjcl/
79	/// pluml) the fixture name happens to equal a valid nameplate moniker — that's
80	/// the convention crucible-scoped tabtargets exploit when imprinting (e.g.,
81	/// `rbw-cC.Charge.{fixture}.sh`). Non-crucible fixtures (regime-*, calibrant-*,
82	/// canonical-*, etc.) carry their fixture name in this slot too, but no
83	/// nameplate-shaped consumer reads them.
84	pub struct rbtdri_Context {
85	    pub(crate) project_root: PathBuf,
86	    pub(crate) fixture: String,
87	    pub(crate) burv_temp_root: PathBuf,
88	    pub(crate) burv_output_root: PathBuf,
89	    pub(crate) invoke_count: u32,
90	}
91	
92	impl rbtdri_Context {
93	    pub fn new(
94	        project_root: &Path,
95	        fixture: &str,
96	        burv_temp_root: &Path,
97	        burv_output_root: &Path,
98	    ) -> Self {
99	        Self {
100	            project_root: project_root.to_path_buf(),
101	            fixture: fixture.to_string(),
102	            burv_temp_root: burv_temp_root.to_path_buf(),
103	            burv_output_root: burv_output_root.to_path_buf(),
104	            invoke_count: 0,
105	        }
106	    }
107	
108	    pub fn fixture(&self) -> &str {
109	        &self.fixture
110	    }
111	
112	    pub fn project_root(&self) -> &Path {
113	        &self.project_root
114	    }
115	}
116	
117	// ── Tabtarget discovery ──────────────────────────────────────
118	
119	/// Find the tabtarget script for a colophon + imprint (nameplate or role).
120	///
121	/// Scans tt/ for files matching `{colophon}.*.{imprint}.sh`.
122	/// Returns error if zero or multiple matches — exactly one must exist.
123	pub fn rbtdri_find_tabtarget(
124	    project_root: &Path,
125	    colophon: &str,
126	    imprint: &str,
127	) -> Result<PathBuf, String> {
128	    let tt_dir = project_root.join("tt");
129	    let prefix = format!("{}.", colophon);
130	    let suffix = format!(".{}.sh", imprint);
131	
132	    let entries = std::fs::read_dir(&tt_dir)
133	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
134	
135	    let matches: Vec<PathBuf> = entries
136	        .filter_map(|entry| entry.ok())
137	        .map(|entry| entry.path())
138	        .filter(|path| {
139	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
140	                name.starts_with(&prefix) && name.ends_with(&suffix)
141	            } else {
142	                false
143	            }
144	        })
145	        .collect();
146	
147	    match matches.len() {
148	        0 => Err(format!(
149	            "rbtdri: no tabtarget for colophon '{}' imprint '{}'",
150	            colophon, imprint
151	        )),
152	        1 => Ok(matches.into_iter().next().unwrap()),
153	        n => Err(format!(
154	            "rbtdri: {} tabtargets match colophon '{}' imprint '{}' — expected exactly one",
155	            n, colophon, imprint
156	        )),
157	    }
158	}
159	
160	/// Find a global tabtarget (no imprint suffix).
161	///
162	/// Scans tt/ for files matching `{colophon}.{frontispiece}.sh` (exactly two dots).
163	/// Rejects files with imprint suffixes (three+ dots).
164	pub fn rbtdri_find_tabtarget_global(
165	    project_root: &Path,
166	    colophon: &str,
167	) -> Result<PathBuf, String> {
168	    let tt_dir = project_root.join("tt");
169	    let prefix = format!("{}.", colophon);
170	
171	    let entries = std::fs::read_dir(&tt_dir)
172	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
173	
174	    let matches: Vec<PathBuf> = entries
175	        .filter_map(|entry| entry.ok())
176	        .map(|entry| entry.path())
177	        .filter(|path| {
178	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
179	                if name.starts_with(&prefix) && name.ends_with(".sh") {
180	                    // Global: no imprint — exactly one part between colophon and .sh
181	                    let middle = &name[prefix.len()..name.len() - 3]; // strip ".sh"
182	                    !middle.contains('.')
183	                } else {
184	                    false
185	                }
186	            } else {
187	                false
188	            }
189	        })
190	        .collect();
191	
192	    match matches.len() {
193	        0 => Err(format!(
194	            "rbtdri: no global tabtarget for colophon '{}'",
195	            colophon
196	        )),
197	        1 => Ok(matches.into_iter().next().unwrap()),
198	        n => Err(format!(
199	            "rbtdri: {} global tabtargets match colophon '{}' — expected exactly one",
200	            n, colophon
201	        )),
202	    }
203	}
204	
205	// ── Tabtarget invocation with BURV isolation ─────────────────
206	
207	/// Internal: execute a resolved tabtarget with BURV isolation and optional extra env vars.
208	fn rbtdri_invoke_impl(
209	    ctx: &mut rbtdri_Context,
210	    tabtarget: &Path,
211	    args: &[&str],
212	    extra_env: &[(&str, &str)],
213	) -> Result<rbtdri_InvokeResult, String> {
214	    let invoke_num = ctx.invoke_count;
215	    ctx.invoke_count += 1;
216	
217	    let dir_name = rbtdri_invoke_dir_name(invoke_num);
218	    let burv_output = ctx.burv_output_root.join(&dir_name);
219	    let burv_temp = ctx.burv_temp_root.join(&dir_name);
220	
221	    std::fs::create_dir_all(&burv_output)
222	        .map_err(|e| format!("rbtdri: failed to create BURV output dir: {}", e))?;
223	    std::fs::create_dir_all(&burv_temp)
224	        .map_err(|e| format!("rbtdri: failed to create BURV temp dir: {}", e))?;
225	
226	    let mut cmd = Command::new(tabtarget);
227	    cmd.args(args)
228	        .current_dir(&ctx.project_root)
229	        .env("BURV_OUTPUT_ROOT_DIR", rbtdrx_native_to_posix(&burv_output))
230	        .env("BURV_TEMP_ROOT_DIR", rbtdrx_native_to_posix(&burv_temp));
231	
232	    for (key, value) in extra_env {
233	        cmd.env(key, value);
234	    }
235	
236	    let output = cmd
237	        .output()
238	        .map_err(|e| format!("rbtdri: failed to execute '{}': {}", tabtarget.display(), e))?;
239	
240	    Ok(rbtdri_InvokeResult {
241	        stdout: String::from_utf8_lossy(&output.stdout).into_owned(),
242	        stderr: String::from_utf8_lossy(&output.stderr).into_owned(),
243	        exit_code: output.status.code().unwrap_or(-1),
244	        burv_output,
245	    })
246	}
247	
248	/// Invoke a fixture-imprinted tabtarget (colophon + ctx.fixture). For crucible
249	/// fixtures the fixture name is also a nameplate moniker, which is the
250	/// imprint shape this resolves against.
251	pub fn rbtdri_invoke(
252	    ctx: &mut rbtdri_Context,
253	    colophon: &str,
254	    args: &[&str],
255	) -> Result<rbtdri_InvokeResult, String> {
256	    let tabtarget = rbtdri_find_tabtarget(&ctx.project_root, colophon, &ctx.fixture)?;
257	    rbtdri_invoke_impl(ctx, &tabtarget, args, &[])
258	}
259	
260	/// Invoke a global tabtarget (no imprint) with optional extra environment variables.
261	pub fn rbtdri_invoke_global(
262	    ctx: &mut rbtdri_Context,
263	    colophon: &str,
264	    args: &[&str],
265	    extra_env: &[(&str, &str)],
266	) -> Result<rbtdri_InvokeResult, String> {
267	    let tabtarget = rbtdri_find_tabtarget_global(&ctx.project_root, colophon)?;
268	    rbtdri_invoke_impl(ctx, &tabtarget, args, extra_env)
269	}
270	
271	/// Invoke a tabtarget with an explicit imprint (overrides ctx.fixture for discovery).
272	pub fn rbtdri_invoke_imprint(
273	    ctx: &mut rbtdri_Context,
274	    colophon: &str,
275	    imprint: &str,
276	    args: &[&str],
277	) -> Result<rbtdri_InvokeResult, String> {
278	    let tabtarget = rbtdri_find_tabtarget(&ctx.project_root, colophon, imprint)?;
279	    rbtdri_invoke_impl(ctx, &tabtarget, args, &[])
280	}
281	
282	// ── BURV fact file reading ───────────────────────────────────
283	
284	/// Read a fact file from a tabtarget's BURV output directory.
285	/// Fact files are single-line values written by tabtargets to BURD_OUTPUT_DIR,
286	/// which is BURV_OUTPUT_ROOT_DIR/current per BUK dispatch convention.
287	pub fn rbtdri_read_burv_fact(
288	    result: &rbtdri_InvokeResult,
289	    fact_name: &str,
290	) -> Result<String, String> {
291	    let path = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR).join(fact_name);
292	    let content = std::fs::read_to_string(&path)
293	        .map_err(|e| format!("rbtdri: cannot read fact '{}' from {}: {}", fact_name, path.display(), e))?;
294	    let trimmed = content.trim().to_string();
295	    if trimmed.is_empty() {
296	        return Err(format!("rbtdri: fact '{}' is empty in {}", fact_name, path.display()));
297	    }
298	    Ok(trimmed)
299	}
300	
301	/// Enumerate multi-fact files in a tabtarget's BURV output directory.
302	/// Multi-facts follow the convention `<root>.<ext>` written by buf_write_fact_multi;
303	/// returns the sorted list of roots whose files have the requested extension.
304	/// Returns an empty Vec if no matching files exist.
305	pub fn rbtdri_read_burv_facts_multi(
306	    result: &rbtdri_InvokeResult,
307	    extension: &str,
308	) -> Result<Vec<String>, String> {
309	    let dir = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
310	    let entries = std::fs::read_dir(&dir).map_err(|e| {
311	        format!(
312	            "rbtdri: cannot enumerate fact dir {}: {}",
313	            dir.display(),
314	            e
315	        )
316	    })?;
317	    let suffix = format!(".{}", extension);
318	    let mut roots: Vec<String> = entries
319	        .filter_map(|entry| entry.ok())
320	        .filter_map(|entry| entry.file_name().into_string().ok())
321	        .filter_map(|name| name.strip_suffix(&suffix).map(str::to_string))
322	        .collect();
323	    roots.sort();
324	    Ok(roots)
325	}
326	
327	// ── Ifrit verdict parsing ────────────────────────────────────
328	
329	/// Ifrit verdict wire protocol: ifrit prints exactly one line matching
330	/// `IFRIT_VERDICT: PASS` or `IFRIT_VERDICT: FAIL <detail>` to stdout.
331	/// Missing verdict line is always a failure — no silent pass-through.
332	pub fn rbtdri_parse_ifrit_verdict(stdout: &str, exit_code: i32) -> rbtdre_Verdict {
333	    for line in stdout.lines() {
334	        let trimmed = line.trim();
335	        if let Some(rest) = trimmed.strip_prefix("IFRIT_VERDICT:") {
336	            let rest = rest.trim();
337	            if rest.starts_with("PASS") {
338	                return rbtdre_Verdict::Pass;
339	            }
340	            if let Some(detail) = rest.strip_prefix("FAIL") {
341	                let detail = detail.trim();
342	                if detail.is_empty() {
343	                    return rbtdre_Verdict::Fail("ifrit reported failure".to_string());
344	                }
345	                return rbtdre_Verdict::Fail(detail.to_string());
346	            }
347	        }
348	    }
349	
350	    if exit_code == 0 {
351	        rbtdre_Verdict::Fail("ifrit exited 0 but no verdict line found".to_string())
352	    } else {
353	        rbtdre_Verdict::Fail(format!("ifrit exited {} with no verdict line", exit_code))
354	    }
355	}
356	
357	/// Invoke the ifrit binary inside a charged bottle via the bark tabtarget.
358	/// The attack selector argument tells ifrit which attack module to run.
359	/// Returns a test verdict based on ifrit's stdout verdict line and exit code.
360	pub fn rbtdri_invoke_ifrit(
361	    ctx: &mut rbtdri_Context,
362	    attack_selector: &str,
363	) -> Result<rbtdre_Verdict, String> {
364	    let result = rbtdri_invoke(ctx, RBTDGC_CRUCIBLE_BARK, &[RBTDRI_IFRIT_BINARY, attack_selector])?;
365	    Ok(rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code))
366	}
